from flask import Flask, send_file, abort
import os

app = Flask(__name__)

@app.route('/api/invoices/<int:invoice_id>/download', methods=['GET'])
def download_invoice(invoice_id):
    invoices_dir = "/path/to/your/invoices"  # Update this to the path where your PDFs are stored
    try:
        return send_file(os.path.join(invoices_dir, f'{invoice_id}.pdf'), as_attachment=True)
    except FileNotFoundError:
        abort(404)  # Return a 404 error if the invoice file does not exist
        
if __name__ == '__main__':
    app.run(debug=True)